<body>
<div class="card">
  <div class="logo"><?= htmlspecialchars($appName) ?></div>

  <?php if ($success): ?>
    <h1>Password set!</h1>
    <div class="alert alert-success">Your password has been updated. You can now log in.</div>
    <div class="back"><a href="<?= htmlspecialchars($homeUrl) ?>">← Go to the app</a></div>

  <?php elseif ($error): ?>
    <h1>Reset link problem</h1>
    <div class="alert alert-error"><?= htmlspecialchars($error) ?></div>
    <div class="back"><a href="<?= htmlspecialchars($homeUrl) ?>">← Back to login</a></div>

  <?php else: ?>
    <h1>Set your password</h1>
    <form method="post">
      <input type="hidden" name="token" value="<?= htmlspecialchars($token) ?>">
      <label for="password">New password</label>
      <input type="password" id="password" name="password" required minlength="6" autofocus autocomplete="new-password">
      <p class="hint">At least 6 characters</p>
      <label for="password2">Confirm password</label>
      <input type="password" id="password2" name="password2" required autocomplete="new-password">
      <button type="submit">Set Password</button>
    </form>
    <div class="back"><a href="<?= htmlspecialchars($homeUrl) ?>">← Back to login</a></div>
  <?php endif; ?>
</div>
</body>
</html>
